"use strict";module.exports=function(n){const{pluginName:i,ruleId:e}=n;return`\nA configuration object specifies rule "${e}", but could not find plugin "${i}".\n\nCommon causes of this problem include:\n\n1. The "${i}" plugin is not defined in your configuration file.\n2. The "${i}" plugin is not defined within the same configuration object in which the "${e}" rule is applied.\n`.trimStart()};